import { Injectable } from '@angular/core';
import { Invoice } from '../models/invoice';
import { InvoiceLine } from '../models/invoice-line';

export interface InvoiceTotals {
  totalHT: number;
  totalTVA: number;
  totalTTC: number;
  remise: number;
  totalHTApresRemise: number;
  totalTVAApresRemise: number;
}

@Injectable({
  providedIn: 'root'
})
export class InvoiceCalcService {
  lineHT(line: InvoiceLine): number {
    const qty = Number(line.quantite) || 0;
    const pu = Number(line.prixUnitaire) || 0;
    return this.round(qty * pu);
  }

  lineTVA(line: InvoiceLine): number {
    const rate = Number(line.tvaRate) || 0;
    return this.round(this.lineHT(line) * (rate / 100));
  }

  lineTTC(line: InvoiceLine): number {
    return this.round(this.lineHT(line) + this.lineTVA(line));
  }

  totals(invoice: Invoice): InvoiceTotals {
    const lines = invoice.lignes ?? [];
    const totalHT = this.round(lines.reduce((sum, line) => sum + this.lineHT(line), 0));
    const totalTVA = this.round(lines.reduce((sum, line) => sum + this.lineTVA(line), 0));

    const remiseValue = Number(invoice.remiseValue) || 0;
    const remiseType = invoice.remiseType ?? 'montant';
    let remise = 0;

    if (remiseValue > 0) {
      remise = remiseType === 'pourcentage' ? totalHT * (remiseValue / 100) : remiseValue;
    }

    remise = this.round(Math.min(remise, totalHT + totalTVA));

    if (invoice.remiseAvantTVA !== false) {
      const totalHTApresRemise = this.round(Math.max(totalHT - remise, 0));
      const ratio = totalHT > 0 ? totalHTApresRemise / totalHT : 0;
      const totalTVAApresRemise = this.round(totalTVA * ratio);
      const totalTTC = this.round(totalHTApresRemise + totalTVAApresRemise);

      return {
        totalHT,
        totalTVA,
        totalTTC,
        remise,
        totalHTApresRemise,
        totalTVAApresRemise
      };
    }

    const totalTTC = this.round(Math.max(totalHT + totalTVA - remise, 0));

    return {
      totalHT,
      totalTVA,
      totalTTC,
      remise,
      totalHTApresRemise: totalHT,
      totalTVAApresRemise: totalTVA
    };
  }

  private round(value: number): number {
    return Math.round((value + Number.EPSILON) * 100) / 100;
  }
}
